from typing import List, Optional

def module_file_structure_py_files_basic(data: List[int]) -> List[int]:
    """Implement basic module file structure (.py files) logic."""
    if not data:
        return []
    return [x * 2 for x in data]

if __name__ == "__main__":
    sample = [1, 2, 3, 4, 5]
    result = module_file_structure_py_files_basic(sample)
    print(f"Result: {result}")

import logging
from typing import List, Any

logging.basicConfig(level=logging.INFO)

def module_file_structure_py_files_intermediate(data: List[Any]) -> List[int]:
    """Advanced module file structure (.py files) with error handling."""
    if not isinstance(data, list):
        raise TypeError("data must be a list")
    if not data:
        logging.warning("Empty data provided")
        return []
    result = []
    for item in data:
        try:
            result.append(int(item) * 2)
        except (ValueError, TypeError):
            logging.warning(f"Skipping invalid item: {item}")
            continue
    return result

def module_file_structure_py_files_fixed(data):
    """Process data (bugs fixed)."""
    result = []
    for i in range(len(data)):
        result.append(data[i] * 2)
    return result

if __name__ == "__main__":
    data = [1, 2, 3]
    result = module_file_structure_py_files_fixed(data)
    print(f"Result: {result}")
